UPDATE POST
SET VIEWS = VIEWS + 1
WHERE P_NUMBER = #{id}

UPDATE POST
SET P_TITLE = #{rTitle}, CONTENTS = #{rContents}
WHERE P_NUMBER = #{rNumber} AND USER_ID = #{userId}

UPDATE POST
SET P_STATUS = 'N'
WHERE P_NUMBER = #{rNumber}

UPDATE REPLY
SET COMMENTS = #{comments}
WHERE C_NUMBER = #{cNumber} AND USER_ID = #{userId} AND C_STATUS = 'Y'

UPDATE REPLY
SET C_STATUS = 'N'
WHERE C_NUMBER = #{cnum}

